using namespace std;
int n, q, aa[100005];
//60分
int gcd(int x, int y) {
	if (y == 0) return x;
	return gcd(y, x % y);
}
int big_gcd_one(int x) {
	int ans = gcd(aa[1] + x, aa[2] + x);
	for (int i = 3; i <= n; i++) {
		ans = gcd(ans, aa[i] + x);
		if (ans == 1) return 1;
	}
	return ans;
}
