int find_min(int (&a)[100005], int n, int x) {
	int minn = INT_MAX;
	for (int i = 1; i <= n; i++) {
		minn = min(minn, a[i] + x);
	}
	return minn;
}
int big_gcd_two(int x) {
	int minn = find_min(aa, n, x), flag = 0;
	for (int i = 1; i <= minn; i++) {
		if (minn != minn / i * i) {
			flag = 1;
			for (int j = 1; j <= n; j++) {
				if ((aa[i] + x) % (minn / i) != 0) {
					flag = 0;
					break;
				}
			}
			if (flag == 1) {
				return minn / i;
			}
		}
	}


