int big_gcd_three() {
	int ans = gcd(abs(aa[2]-aa[1]), abs(aa[3]-aa[1]));
	for (int i = 4; i <= n; i++) {
		ans = gcd(ans, abs(aa[i]-aa[1]));
		if (ans == 1) return 1;
	}
	return ans;
}
